742: impl<I: Interner> From<ty::AliasTy<I>> for AliasTerm<I> {
743:     fn from(ty: ty::AliasTy<I>) -> Self {
744:         AliasTerm { args: ty.args, def_id: ty.def_id, _use_alias_term_new_instead: () }
745:     }
746: }
747: 
748: impl<I: Interner> From<ty::UnevaluatedConst<I>> for AliasTerm<I> {
749:     fn from(ct: ty::UnevaluatedConst<I>) -> Self {
750:         AliasTerm { args: ct.args, def_id: ct.def.into(), _use_alias_term_new_instead: () }
751:     }
752: }
