821: impl<I: Interner> fmt::Debug for ProjectionPredicate<I> {
822:     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
823:         write!(f, "ProjectionPredicate({:?}, {:?})", self.projection_term, self.term)
824:     }
825: }
