60: pub struct TraitRef<I: Interner> {
61:     pub def_id: I::TraitId,
62:     pub args: I::GenericArgs,
63:     /// This field exists to prevent the creation of `TraitRef` without
64:     /// calling [`TraitRef::new_from_args`].
