283:     /// E.g., `Iterator`.
284:     Trait(ExistentialTraitRef<I>),
285:     /// E.g., `Iterator::Item = T`.
286:     Projection(ExistentialProjection<I>),
287:     /// E.g., `Send`.
288:     AutoTrait(I::TraitId),
289: }
