671:     pub fn with_replaced_self_ty(self, interner: I, self_ty: I::Ty) -> Self {
672:         AliasTerm::new(
673:             interner,
674:             self.def_id,
675:             [self_ty.into()].into_iter().chain(self.args.iter().skip(1)),
676:         )
677:     }
